INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('What are the three main layers of the Earth?', '["Crust, mantle, and core", "Crust, lithosphere, and asthenosphere", "Crust, magma, and iron", "Crust, tectonic plates, and core"]', 'A', 'Earth has three main layers: the crust (outermost), the mantle (middle), and the core (innermost, divided into outer liquid and inner solid core).', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the theory that explains the movement of Earth''s continents?', '["Plate tectonics", "Continental drift alone", "Pangaea theory", "Seafloor spreading"]', 'A', 'Plate tectonics is the scientific theory explaining that Earth''s lithosphere is divided into tectonic plates that move and interact. Continental drift, proposed by Wegener, was an earlier concept incorporated into plate tectonics.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What type of rock is formed from cooled magma or lava?', '["Igneous rock", "Sedimentary rock", "Metamorphic rock", "Crystalline rock"]', 'A', 'Igneous rocks form when magma (underground) or lava (surface) cools and solidifies. Examples: granite (intrusive) and basalt (extrusive).', 'Science', 'Earth Science', 'easy', 'secondary'),
('What type of rock is formed by heat and pressure transforming existing rocks?', '["Metamorphic rock", "Igneous rock", "Sedimentary rock", "Volcanic rock"]', 'A', 'Metamorphic rocks form when existing rocks (igneous, sedimentary, or other metamorphic) are transformed by intense heat and pressure. Examples: marble (from limestone), quartzite (from sandstone).', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the term for molten rock beneath Earth''s surface?', '["Magma", "Lava", "Obsidian", "Basalt"]', 'A', 'Magma is molten rock beneath Earth''s surface. When it reaches the surface and flows out, it is called lava.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What causes earthquakes?', '["Movement and friction along tectonic plate boundaries", "Volcanic eruptions only", "Ocean currents", "Changes in atmospheric pressure"]', 'A', 'Earthquakes are caused by the sudden release of energy in Earth''s crust, usually from the movement and friction of tectonic plates at faults.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the term for the original position of an earthquake''s energy release underground?', '["Focus (or hypocenter)", "Epicenter", "Fault line", "Seismic zone"]', 'A', 'The focus (hypocenter) is the point underground where an earthquake originates. The epicenter is the point on the surface directly above the focus.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What instrument is used to measure earthquakes?', '["Seismograph", "Barometer", "Richter scale instrument", "Thermometer"]', 'A', 'A seismograph records the intensity and duration of seismic waves. The Richter scale and moment magnitude scale measure earthquake intensity.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the water cycle?', '["The continuous movement of water through evaporation, condensation, and precipitation", "The movement of water in oceans only", "Groundwater flowing to the sea", "Rain falling and evaporating"]', 'A', 'The water cycle (hydrological cycle) describes the continuous movement of water through evaporation, condensation, precipitation, collection, and transpiration.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the layer of the atmosphere closest to Earth''s surface?', '["Troposphere", "Stratosphere", "Mesosphere", "Thermosphere"]', 'A', 'The troposphere is the lowest layer of Earth''s atmosphere (0-12 km), where weather occurs and where most of Earth''s air mass is concentrated.', 'Science', 'Earth Science', 'easy', 'secondary'),
('Where is the ozone layer located?', '["Stratosphere", "Troposphere", "Mesosphere", "Thermosphere"]', 'A', 'The ozone layer is in the stratosphere (15-35 km altitude), protecting Earth from the Sun''s harmful ultraviolet (UV) radiation.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is the greenhouse effect?', '["The trapping of heat by atmospheric gases, warming Earth''s surface", "A method of growing plants indoors", "The reflection of sunlight by ice caps", "The cooling of Earth by clouds"]', 'A', 'The greenhouse effect is the process where greenhouse gases (CO₂, methane, water vapor) trap heat from the sun, warming Earth''s surface. Enhanced greenhouse effect causes climate change.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What type of plate boundary is where two plates move apart?', '["Divergent boundary", "Convergent boundary", "Transform boundary", "Subduction zone"]', 'A', 'At divergent boundaries, plates move apart, creating rift valleys (on land) or mid-ocean ridges (underwater). New seafloor forms through seafloor spreading.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is a "fault"?', '["A fracture in Earth''s crust where rocks have moved", "A type of volcano", "A sedimentary layer", "A type of mineral"]', 'A', 'A fault is a fracture or zone of fractures in Earth''s crust where blocks of rock have moved relative to each other, often along tectonic plate boundaries.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is sedimentary rock formed from?', '["Compressed layers of sediment (sand, mud, shells)", "Cooled lava", "Heat and pressure on existing rocks", "Chemical reactions in the mantle"]', 'A', 'Sedimentary rocks form from the compaction and cementation of sediment (rock fragments, minerals, organic materials). Examples: sandstone, limestone, shale.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the "Ring of Fire"?', '["A zone of earthquakes and volcanoes around the Pacific Ocean", "A volcanic island chain in the Atlantic", "A type of meteor impact zone", "The equatorial region of Earth"]', 'A', 'The Ring of Fire is a horseshoe-shaped zone around the Pacific Ocean with intense seismic and volcanic activity, due to multiple tectonic plate boundaries.', 'Science', 'Earth Science', 'easy', 'secondary'),
('The Philippines lies in the Pacific Ring of Fire. This makes it prone to:', '["Earthquakes and volcanic eruptions", "Tornadoes and blizzards", "Desert formation", "Tidal waves only"]', 'A', 'The Philippines'' location in the Ring of Fire means it experiences frequent earthquakes and volcanic activity, with active volcanoes like Mayon and Taal.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the process by which water vapor changes into liquid water?', '["Condensation", "Evaporation", "Precipitation", "Transpiration"]', 'A', 'Condensation is the process where water vapor (gas) cools and converts to liquid water, forming clouds, fog, and dew.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What type of plate boundary causes mountain ranges to form?', '["Convergent boundary (continental collision)", "Divergent boundary", "Transform boundary", "Subduction zone"]', 'A', 'When two continental plates collide at a convergent boundary, neither subducts; instead, the crust crumples upward forming mountain ranges (like the Himalayas).', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is the most abundant gas in Earth''s atmosphere?', '["Nitrogen (78%)", "Oxygen (21%)", "Carbon dioxide (0.04%)", "Argon (0.93%)"]', 'A', 'Earth''s atmosphere is composed of about 78% nitrogen (N₂), 21% oxygen (O₂), and 0.93% argon, with trace amounts of other gases.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is a "tsunami"?', '["A series of ocean waves caused by underwater earthquakes or volcanic eruptions", "An extremely powerful typhoon", "A type of storm surge", "A giant freshwater flood"]', 'A', 'A tsunami is a series of large ocean waves caused by sudden displacement of water, typically from underwater earthquakes, volcanic eruptions, or landslides.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the rock cycle?', '["The continuous process by which rocks are formed, changed, and reformed", "The formation of rocks only", "The study of minerals", "The erosion of rocks by water"]', 'A', 'The rock cycle describes how rocks are continuously transformed between igneous, sedimentary, and metamorphic types through geological processes.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the term for the supercontinent that is believed to have existed about 300 million years ago?', '["Pangaea", "Gondwana", "Laurasia", "Tethys"]', 'A', 'Pangaea (meaning "all land") was the supercontinent that existed about 300 million years ago before it broke apart into the continents we know today.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is the lithosphere?', '["The solid outer layer of Earth including the crust and upper mantle", "Only Earth''s crust", "The liquid outer core", "All of Earth''s water"]', 'A', 'The lithosphere is the rigid outermost shell of Earth, comprising the crust and the uppermost part of the mantle. It is broken into tectonic plates.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is "erosion"?', '["The wearing away of rock or soil by natural forces", "The formation of new rock", "The deposition of sediment", "The movement of tectonic plates"]', 'A', 'Erosion is the process of wearing away or removing rock, soil, and other materials from Earth''s surface by wind, water, ice, or gravity.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the Richter scale used to measure?', '["The magnitude of earthquakes", "Wind speed", "Ocean wave height", "Volcanic eruption intensity"]', 'A', 'The Richter scale (now largely replaced by the moment magnitude scale) measures the magnitude (energy release) of earthquakes. Each whole number increase represents 10 times greater ground shaking.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is the most abundant mineral in Earth''s crust?', '["Feldspar", "Quartz", "Mica", "Olivine"]', 'A', 'Feldspar is the most abundant mineral group in Earth''s crust (about 50-60%), followed by quartz. Feldspars are silicate minerals.', 'Science', 'Earth Science', 'hard', 'secondary'),
('What is the aurora borealis (Northern Lights)?', '["Light display caused by solar particles interacting with Earth''s atmosphere", "Reflected sunlight from ice", "Volcanic light emissions", "Lightning in the stratosphere"]', 'A', 'The aurora borealis is a natural light display in Earth''s polar regions caused by charged solar particles colliding with atmospheric gases in the magnetosphere.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is "weathering"?', '["The breaking down of rocks by physical or chemical processes", "The movement of weathered material", "The formation of clouds", "The erosion by wind"]', 'A', 'Weathering is the breaking down or dissolving of rocks and minerals on Earth''s surface. Physical weathering breaks rocks apart; chemical weathering alters their composition.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is El Niño?', '["A warming of Pacific Ocean surface temperatures that affects global weather", "A cold ocean current", "A type of hurricane in the Pacific", "A wind pattern in the Indian Ocean"]', 'A', 'El Niño is the periodic warming of Pacific Ocean surface temperatures (especially near South America), causing disruptions in global weather patterns including droughts and heavy rainfall.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is the term for a vent in Earth''s crust that releases magma, gases, and ash?', '["Volcano", "Geyser", "Fault", "Hot spring"]', 'A', 'A volcano is an opening in Earth''s crust through which magma, ash, gases, and rock fragments erupt. The Philippines has many active volcanoes including Mayon, Taal, and Kanlaon.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What layer of Earth is primarily responsible for Earth''s magnetic field?', '["Outer core (liquid iron and nickel)", "Inner core", "Mantle", "Crust"]', 'A', 'Earth''s magnetic field is generated by the movement of molten iron and nickel in the liquid outer core, acting as a dynamo.', 'Science', 'Earth Science', 'hard', 'secondary'),
('What type of wave is produced by earthquakes that travels through Earth?', '["Seismic waves", "Sound waves", "Electromagnetic waves", "Radio waves"]', 'A', 'Earthquakes produce seismic waves (body waves: P-waves and S-waves; surface waves: Love and Rayleigh waves) that travel through Earth and along its surface.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is the "hydrosphere"?', '["All of Earth''s water, including oceans, lakes, and ice", "The layer of water in the mantle only", "Atmospheric water vapor only", "Underground water only"]', 'A', 'The hydrosphere encompasses all water on, above, and within Earth: oceans, rivers, lakes, groundwater, ice caps, and water vapor.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What percentage of Earth''s surface is covered by water?', '["About 71%", "About 50%", "About 60%", "About 80%"]', 'A', 'Approximately 71% of Earth''s surface is covered by water (mostly the oceans), while 29% is land.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the biosphere?', '["The zone of Earth inhabited by living organisms", "The atmosphere only", "The oceans only", "The land surface only"]', 'A', 'The biosphere encompasses all regions of Earth (land, water, and air) where living organisms exist. It overlaps with the other spheres.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is seafloor spreading?', '["New seafloor crust forms at mid-ocean ridges as plates move apart", "The sinking of ocean floor into trenches", "The movement of fish along the ocean floor", "The erosion of ocean floor by currents"]', 'A', 'Seafloor spreading occurs at mid-ocean ridges where diverging plates separate, magma rises to create new oceanic crust, and the ocean floor spreads outward.', 'Science', 'Earth Science', 'hard', 'secondary'),
('What is the asthenosphere?', '["The partially molten, ductile layer of the upper mantle below the lithosphere", "The outer core", "The solid inner mantle", "Earth''s crust"]', 'A', 'The asthenosphere is the semi-fluid layer of Earth''s upper mantle on which the rigid tectonic plates (lithosphere) float and move.', 'Science', 'Earth Science', 'hard', 'secondary'),
('Which type of seismic wave can travel through liquids?', '["P-waves (primary/compressional)", "S-waves (secondary/shear)", "Both P and S waves", "Neither P nor S waves"]', 'A', 'P-waves (compressional waves) can travel through solids, liquids, and gases. S-waves (shear waves) can only travel through solids — this is how scientists know Earth''s outer core is liquid.', 'Science', 'Earth Science', 'hard', 'secondary'),
('What is the Coriolis effect?', '["The deflection of moving objects (winds, currents) due to Earth''s rotation", "The bending of light by the atmosphere", "Tidal forces from the Moon", "Heat convection in the mantle"]', 'A', 'The Coriolis effect is the apparent deflection of moving objects (wind, ocean currents) due to Earth''s rotation. In the Northern Hemisphere, deflection is to the right.', 'Science', 'Earth Science', 'hard', 'secondary'),
('What causes the seasons on Earth?', '["The tilt of Earth''s axis as it orbits the sun", "Earth''s varying distance from the sun", "The moon''s influence", "Atmospheric changes"]', 'A', 'Earth''s seasons are caused by the 23.5° tilt of its axis relative to its orbital plane. This causes different hemispheres to receive more direct sunlight at different times of year.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is "subduction"?', '["One tectonic plate sinking beneath another at a convergent boundary", "Two plates moving apart", "Two plates sliding past each other", "A plate rising above another"]', 'A', 'Subduction occurs at convergent plate boundaries where a denser oceanic plate sinks beneath a lighter continental plate into the mantle, forming ocean trenches and volcanic arcs.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is the Mohs scale used to measure?', '["Hardness of minerals", "Earthquake magnitude", "Volcanic eruption size", "Ocean depth"]', 'A', 'The Mohs hardness scale (1-10) measures the scratch resistance of minerals. Diamond (10) is the hardest; talc (1) is the softest.', 'Science', 'Earth Science', 'medium', 'secondary'),
('How is ocean depth measured?', '["Sonar (sound navigation and ranging)", "Satellites only", "Diving to the seafloor", "Light sensors"]', 'A', 'Sonar uses sound waves that travel to the ocean floor and bounce back; the time taken determines depth. It is the primary method for mapping ocean floors.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is a "caldera"?', '["A large crater formed by the collapse of a volcano after eruption", "An active volcano vent", "A lava tube", "A hot spring"]', 'A', 'A caldera is a large depression formed when a volcano erupts and the magma chamber empties, causing the summit to collapse. Taal Volcano in the Philippines has a caldera with a lake.', 'Science', 'Earth Science', 'hard', 'secondary'),
('What is the process by which plants release water vapor?', '["Transpiration", "Evaporation", "Condensation", "Precipitation"]', 'A', 'Transpiration is the process by which plants release water vapor through their leaves. Together with evaporation, it is called evapotranspiration.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is the "albedo" of Earth?', '["The fraction of sunlight reflected by Earth''s surface", "The temperature of Earth''s core", "The depth of the ocean", "The density of Earth''s atmosphere"]', 'A', 'Albedo is the fraction of solar radiation reflected back to space. Ice and snow have high albedo (reflect more sunlight); dark forests and oceans have low albedo.', 'Science', 'Earth Science', 'hard', 'secondary'),
('What type of erosion is caused by glaciers?', '["Glacial erosion, which carves U-shaped valleys", "Wind erosion, creating sand dunes", "Water erosion, forming river deltas", "Chemical erosion, dissolving limestone"]', 'A', 'Glacial erosion occurs when glaciers scrape and grind rock as they move, forming U-shaped valleys, fjords, and cirques.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is "acid rain"?', '["Precipitation with higher acidity than normal due to atmospheric pollution", "Rain in acidic soil regions", "A natural form of rain in rainforests", "Rain that tastes sour"]', 'A', 'Acid rain is precipitation (rain, snow, fog) with unusually high acidity caused by sulfur dioxide and nitrogen oxides from burning fossil fuels reacting with atmospheric water.', 'Science', 'Earth Science', 'medium', 'secondary'),
('What is the Philippine Fault Zone?', '["A major active fault system running through the Philippines", "A dormant earthquake zone", "An oceanic trench east of the Philippines", "A volcanic chain in Mindanao"]', 'A', 'The Philippine Fault Zone is a major 1,200 km left-lateral strike-slip fault system running from Luzon to Mindanao. It is responsible for many damaging earthquakes in the country.', 'Science', 'Earth Science', 'hard', 'secondary');
